// Lokality, jejichž PŘESNÁ geometrie už přichází z AOPK – nezakládat je znovu z Málkovy studie.
const GEOM_FROM_AOPK = new Set(['u-kastanku', 'trebovske-steny']);

// Složí seed pro editovatelnou vrstvu: oficiální ZCHÚ + park (s geometrií)
// a lokální VKP/biocentra/biokoridory z Málkovy studie (bez geometrie – tým je zakreslí).
export function areaSeed() {
  const seed = MANAGED_AREAS.map((a) => ({
    seedId: a.kat === 'PřP' ? `park-${a.kod}` : `aopk-${a.kod}`,
    name: a.name,
    type: a.kat === 'PřP' ? 'park' : 'zchu',
    kat: a.kat,
    areaText: a.areaHa ? `${a.areaHa} ha` : '',
    desc: '',
    usopUrl: a.usopUrl || '',
    source: 'aopk',
    geometry: a.geometry,
  }));
  for (const l of LOCALITIES) {
    if (GEOM_FROM_AOPK.has(l.id)) continue; // už pokryto přesnou geometrií z AOPK
    seed.push({
      seedId: `loc-${l.id}`,
      name: l.name,
      type: l.type,
      kat: '',
      areaText: l.area || '',
      desc: l.desc || '',
      usopUrl: '',
      source: 'malek',
      geometry: null, // bez zákresu – zakreslí se ručně v terénu/mapě
    });
  }
  return seed;
}

// Idempotentní import do kolekce „areas". Přidá jen to, co tam podle seedId ještě není.
export async function importProtectedAreas() {
  try {
    await Store.refresh('areas'); // ať známe stav serveru a nezdvojujeme
  } catch {
    /* offline – jedeme z lokální cache */
  }
  const have = new Set(Store.get('areas').map((a) => a.seedId).filter(Boolean));
  let added = 0;
  for (const s of areaSeed()) {
    if (have.has(s.seedId)) continue;
    await Store.add('areas', s);
    added++;
  }
  return added;
}
